t.script:
const BASE_URL_HOME = window.location.origin;
let _qrStream = null;
let _qrMode   = 'bl';         // 'bl' ou 'product'
let _qrPickingId = null;      // utilisé en mode product
let _qrAnimFrame = null;
let _qrLocked = false;        // empêche double-détection

function openQRScanner(mode, pickingId) {
    _qrMode      = mode || 'bl';
    _qrPickingId = pickingId || null;
    _qrLocked    = false;

    const title    = document.getElementById('qr-title');
    const subtitle = document.getElementById('qr-subtitle');
    const status   = document.getElementById('qr-status');
    const overlay  = document.getElementById('qr-overlay');

    if (_qrMode === 'bl') {
        title.innerHTML    = '<i class="fa fa-qrcode"></i> Scanner un BL';
        subtitle.textContent = 'Pointez la caméra vers le QR code du bon de livraison';
    } else {
        title.innerHTML    = '<i class="fa fa-barcode"></i> Scanner un produit';
        subtitle.textContent = 'Pointez la caméra vers le code-barres du produit';
    }
    status.className   = 'qr-status';
    status.textContent = 'Initialisation de la caméra…';
    overlay.classList.add('active');
    _startCamera();
}

function closeQRScanner() {
    _stopCamera();
    document.getElementById('qr-overlay').classList.remove('active');
}

async function _startCamera() {
    const video  = document.getElementById('qr-video');
    const status = document.getElementById('qr-status');
    try {
        _qrStream = await navigator.mediaDevices.getUserMedia({
            video: { facingMode: { ideal: 'environment' }, width: { ideal: 1280 }, height: { ideal: 720 } }
        });
        video.srcObject = _qrStream;
        await video.play();
        status.textContent = 'Recherche de code…';
        _scanLoop();
    } catch (err) {
        status.className   = 'qr-status error';
        if (err.name === 'NotAllowedError') {
            status.textContent = 'Accès caméra refusé. Autorisez la caméra dans les paramètres du navigateur.';
        } else if (err.name === 'NotFoundError') {
            status.textContent = 'Aucune caméra disponible sur cet appareil.';
        } else {
            status.textContent = 'Erreur caméra : ' + err.message;
        }
    }
}

function _stopCamera() {
    if (_qrAnimFrame) { cancelAnimationFrame(_qrAnimFrame); _qrAnimFrame = null; }
    if (_qrStream) {
        _qrStream.getTracks().forEach(t => t.stop());
        _qrStream = null;
    }
    const video = document.getElementById('qr-video');
    if (video) video.srcObject = null;
}

function _scanLoop() {
    if (_qrLocked) return;
    const video  = document.getElementById('qr-video');
    const canvas = document.getElementById('qr-canvas');
    const ctx    = canvas ? canvas.getContext('2d') : null;
    if (!video || !canvas || !ctx) return;

    if (video.readyState >= video.HAVE_ENOUGH_DATA && video.videoWidth > 0) {
        canvas.width  = video.videoWidth;
        canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
        let result = null;
        try { result = jsQR(imageData.data, imageData.width, imageData.height, { inversionAttempts: 'dontInvert' }); }
        catch (_) {}
        if (result && result.data) {
            _qrLocked = true;
            _onCodeDetected(result.data);
            return;
        }
    }
    _qrAnimFrame = requestAnimationFrame(_scanLoop);
}

async function _onCodeDetected(code) {
    const status = document.getElementById('qr-status');
    status.textContent = 'Code détecté : ' + code.substring(0, 40) + '…';

    // Feedback vibration
    if (navigator.vibrate) navigator.vibrate(80);

    if (_qrMode === 'bl') {
        status.textContent = 'Recherche du BL…';
        try {
            const resp = await fetch('/parabox/mobile/livreur/scan/bl', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({jsonrpc:'2.0', method:'call', id:1, params:{code: code}})
            });
            const data = await resp.json();
            const r    = data.result || {};
            if (r.success) {
                status.className   = 'qr-status success';
                status.textContent = 'BL trouvé : ' + r.name + ' — ' + r.partner;
                _stopCamera();
                setTimeout(() => { window.location.href = r.redirect; }, 800);
            } else {
                status.className   = 'qr-status error';
                status.textContent = r.message || 'BL introuvable.';
                setTimeout(() => { _qrLocked = false; _scanLoop(); }, 2500);
            }
        } catch (e) {
            status.className   = 'qr-status error';
            status.textContent = 'Erreur réseau — réessayez.';
            setTimeout(() => { _qrLocked = false; _scanLoop(); }, 2500);
        }
    } else {
        // Mode produit
        status.textContent = 'Vérification du produit…';
        try {
            const resp = await fetch('/parabox/mobile/livreur/scan/product', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({jsonrpc:'2.0', method:'call', id:1,
                    params:{barcode: code, picking_id: _qrPickingId}})
            });
            const data = await resp.json();
            const r    = data.result || {};
            if (r.success) {
                closeQRScanner();
                _highlightProduct(r);
            } else {
                status.className   = 'qr-status error';
                status.textContent = r.message || 'Produit introuvable.';
                setTimeout(() => { _qrLocked = false; _scanLoop(); }, 2500);
            }
        } catch (e) {
            status.className   = 'qr-status error';
            status.textContent = 'Erreur réseau — réessayez.';
            setTimeout(() => { _qrLocked = false; _scanLoop(); }, 2500);
        }
    }
}

function _highlightProduct(product) {
    // Chercher le produit dans la liste par son nom ou référence
    const items = document.querySelectorAll('.product-item');
    let matched = false;
    items.forEach(item => {
        const nameEl = item.querySelector('.product-name');
        if (!nameEl) return;
        const nameText = nameEl.textContent.trim().toLowerCase();
        const searchTerm = (product.name || product.ref || '').toLowerCase();
        if (searchTerm && nameText.includes(searchTerm.substring(0, 15))) {
            item.classList.add('scan-match');
            item.classList.remove('scan-nomatch');
            let badge = item.querySelector('.scan-badge');
            if (!badge) { badge = document.createElement('div'); badge.className = 'scan-badge ok'; item.querySelector('.product-info').appendChild(badge); }
            badge.className = 'scan-badge ok';
            badge.textContent = product.in_bl ? 'Scanné ✓ (' + product.qty_ordered + ')' : 'Trouvé (hors BL)';
            item.scrollIntoView({behavior: 'smooth', block: 'center'});
            matched = true;
        }
    });
    if (!matched) {
        // Afficher alerte si produit non trouvé dans la liste visuelle
        const msg = document.getElementById('action-msg');
        if (msg) {
            msg.className   = 'msg-box msg-error';
            msg.innerHTML   = '<i class="fa fa-times-circle msg-icon"></i><div><strong>' + product.name + '</strong>' +
                              (product.in_bl ? ' — présent dans ce BL' : ' — <strong>absent de ce BL</strong>') + '</div>';
            setTimeout(() => { msg.className = ''; msg.innerHTML = ''; }, 4000);
        }
    }
}

const PICKING_ID = ;
const BASE_URL   = '';

/* ── Envoi OTP ── */
async function sendOtp(btn) {
    const resultDiv   = document.getElementById('otp-result');
    const urlSection  = document.getElementById('sign-url-section');
    const urlDisplay  = document.getElementById('sign-url-display');
    const origText    = btn ? btn.innerHTML : '';

    if (btn) {
        btn.disabled = true;
        btn.innerHTML = '<span class="spinner"></span> Envoi en cours…';
    }

    try {
        const resp = await fetch(`${BASE_URL}/parabox/mobile/livreur/bl/${PICKING_ID}/send-otp`, {
            method: 'POST',
            headers: {'Content-Type': 'application/json', 'X-Requested-With': 'XMLHttpRequest'},
            body: JSON.stringify({jsonrpc: '2.0', method: 'call', id: 1, params: {}})
        });
        const data   = await resp.json();
        const result = data.result || {};

        if (result.success) {
            if (resultDiv) {
                resultDiv.className = 'msg-box msg-success';
                resultDiv.innerHTML = '<i class="fa fa-check-circle msg-icon"></i><div>' + result.message + '</div>';
            }
            if (urlSection && result.sign_url) {
                urlDisplay.innerHTML = '<strong>URL de signature :</strong><br/>' + result.sign_url;
                urlSection.style.display = 'block';
            }
            if (btn) {
                btn.disabled  = false;
                btn.innerHTML = '<i class="fa fa-repeat"></i> Renvoyer l\'OTP';
                btn.className = 'btn-mobile btn-warning';
            }
        } else {
            if (resultDiv) {
                resultDiv.className = 'msg-box msg-error';
                resultDiv.innerHTML = '<i class="fa fa-times-circle msg-icon"></i><div>' + (result.message || 'Erreur inconnue') + '</div>';
            }
            if (btn) { btn.disabled = false; btn.innerHTML = origText; }
        }
    } catch (e) {
        if (resultDiv) {
            resultDiv.className = 'msg-box msg-error';
            resultDiv.innerHTML = '<i class="fa fa-times-circle msg-icon"></i><div>Erreur réseau — vérifiez votre connexion WiFi.</div>';
        }
        if (btn) { btn.disabled = false; btn.innerHTML = origText; }
    }
}

/* ── Détection annulation en temps réel (polling toutes les 15s) ── */
async function checkCancellation() {
    try {
        const resp = await fetch(`${BASE_URL}/parabox/mobile/livreur/bl/${PICKING_ID}/status`, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({jsonrpc: '2.0', method: 'call', id: 1, params: {}})
        });
        const data   = await resp.json();
        const result = data.result || {};
        if (result.cancelled) {
            // Afficher bannière d'annulation sans recharger brutalement
            const container = document.querySelector('.mob-container');
            if (container) {
                container.innerHTML = '<div class="alert-banner" style="margin-top:24px;">' +
                    '<i class="fa fa-times-circle" style="font-size:28px;color:var(--accent);"></i>' +
                    '<div><div>Ce bon de livraison vient d\'être <strong>annulé</strong> par le magasinier.</div>' +
                    '<div style="margin-top:8px;"><a href="' + BASE_URL + '/parabox/mobile/livreur" ' +
                    'style="color:inherit;font-weight:600;">← Revenir à la liste</a></div></div></div>';
            }
            clearInterval(pollInterval);
        }
    } catch (_) { /* ignorer les erreurs réseau */ }
}

// Démarrer le polling seulement si le BL n'est pas déjà annulé ou terminé
const blState = '';
let pollInterval = null;
if (blState !== 'done' &amp;&amp; blState !== 'cancel') {
    pollInterval = setInterval(checkCancellation, 15000);
}

/* ── QR Scanner partagé — mode produit sur cette page ── */
let _qrStream2 = null, _qrAnimFrame2 = null, _qrLocked2 = false;
const _qrPickingId2 = PICKING_ID;

function openQRScanner(mode, pickingId) {
    _qrLocked2 = false;
    const status = document.getElementById('qr-status');
    status.className   = 'qr-status';
    status.textContent = 'Initialisation de la caméra…';
    document.getElementById('qr-overlay').classList.add('active');
    _startCamera2();
}

function closeQRScanner() {
    _stopCamera2();
    document.getElementById('qr-overlay').classList.remove('active');
}

async function _startCamera2() {
    const video  = document.getElementById('qr-video');
    const status = document.getElementById('qr-status');
    try {
        _qrStream2 = await navigator.mediaDevices.getUserMedia({
            video: { facingMode: { ideal: 'environment' }, width: { ideal: 1280 }, height: { ideal: 720 } }
        });
        video.srcObject = _qrStream2;
        await video.play();
        status.textContent = 'Pointez vers le code-barres du produit…';
        _scanLoop2();
    } catch (err) {
        status.className   = 'qr-status error';
        status.textContent = (err.name === 'NotAllowedError')
            ? 'Accès caméra refusé. Autorisez la caméra dans les paramètres.'
            : 'Caméra indisponible : ' + err.message;
    }
}

function _stopCamera2() {
    if (_qrAnimFrame2) { cancelAnimationFrame(_qrAnimFrame2); _qrAnimFrame2 = null; }
    if (_qrStream2) { _qrStream2.getTracks().forEach(t => t.stop()); _qrStream2 = null; }
    const v = document.getElementById('qr-video');
    if (v) v.srcObject = null;
}

function _scanLoop2() {
    if (_qrLocked2) return;
    const video  = document.getElementById('qr-video');
    const canvas = document.getElementById('qr-canvas');
    const ctx    = canvas ? canvas.getContext('2d') : null;
    if (!video || !canvas || !ctx) return;
    if (video.readyState >= video.HAVE_ENOUGH_DATA && video.videoWidth > 0) {
        canvas.width = video.videoWidth; canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        let result = null;
        try { result = jsQR(ctx.getImageData(0,0,canvas.width,canvas.height).data, canvas.width, canvas.height); } catch(_){}
        if (result && result.data) { _qrLocked2 = true; _onProductScanned(result.data); return; }
    }
    _qrAnimFrame2 = requestAnimationFrame(_scanLoop2);
}

async function _onProductScanned(code) {
    if (navigator.vibrate) navigator.vibrate(80);
    const status = document.getElementById('qr-status');
    status.textContent = 'Vérification : ' + code.substring(0, 30) + '…';
    try {
        const resp = await fetch('/parabox/mobile/livreur/scan/product', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({jsonrpc:'2.0',method:'call',id:1,
                params:{barcode: code, picking_id: _qrPickingId2}})
        });
        const data = await resp.json();
        const r    = data.result || {};
        if (r.success) {
            closeQRScanner();
            _highlightProduct2(r);
        } else {
            status.className   = 'qr-status error';
            status.textContent = r.message || 'Produit introuvable.';
            setTimeout(() => { _qrLocked2 = false; _scanLoop2(); }, 2500);
        }
    } catch(e) {
        status.className   = 'qr-status error';
        status.textContent = 'Erreur réseau.';
        setTimeout(() => { _qrLocked2 = false; _scanLoop2(); }, 2500);
    }
}

function _highlightProduct2(product) {
    const items = document.querySelectorAll('.product-item');
    let matched = false;
    const search = (product.ref || product.name || '').toLowerCase().substring(0, 20);
    items.forEach(item => {
        const nameEl = item.querySelector('.product-name');
        if (!nameEl) return;
        if (nameEl.textContent.trim().toLowerCase().includes(search)) {
            item.classList.add('scan-match'); item.classList.remove('scan-nomatch');
            let badge = item.querySelector('.scan-badge');
            if (!badge) { badge = document.createElement('div'); item.querySelector('.product-info').appendChild(badge); }
            badge.className   = 'scan-badge ok';
            badge.textContent = product.in_bl ? 'Scanné ✓ (qté: ' + product.qty_ordered + ')' : 'Trouvé (hors BL)';
            item.scrollIntoView({behavior:'smooth', block:'center'});
            matched = true;
        }
    });
    if (!matched) {
        const msg = document.getElementById('action-msg');
        if (msg) {
            msg.className = product.in_bl ? 'msg-box msg-success' : 'msg-box msg-error';
            msg.innerHTML = '<i class="fa fa-' + (product.in_bl ? 'check-circle' : 'times-circle') + ' msg-icon"></i>' +
                '<div><strong>' + product.name + '</strong> — ' +
                (product.in_bl ? 'Présent dans ce BL (qté: ' + product.qty_ordered + ')' : 'Absent de ce BL') + '</div>';
            setTimeout(() => { msg.className=''; msg.innerHTML=''; }, 4000);
        }
    }
}
